package com.i2i.voltwise.home;
import jakarta.validation.Valid; import jakarta.validation.constraints.*; import java.math.BigDecimal; import java.time.LocalDate; import java.util.*;
public final class HomeDtos { private HomeDtos(){} public record ApplianceRequest(@NotBlank String name,@DecimalMin("1") BigDecimal safeWattLimit){} public record CreateHomeRequest(@NotBlank String name,@Email @NotBlank String email,@DecimalMin("1") BigDecimal budgetLimit,@DecimalMin("0") BigDecimal baseTariff,@DecimalMin("1") BigDecimal penaltyMultiplier,@NotEmpty List<@Valid ApplianceRequest> appliances){} public record CreatedHome(UUID id,String name){} public record ApplianceStatus(UUID id,String name,double watts,double safeWattLimit,int breachCount,boolean anomalous){} public record HomeStatus(UUID id,String name,String email,double energyKwh,double cost,double budgetLimit,double budgetPercent,boolean penalty,boolean quotaWarning,List<ApplianceStatus> appliances){} public record DailyTrend(LocalDate day,double energyKwh,double cost){} }
